-- Import the remaining public posts from the former PCA Youth Center blog.
-- Text, dates, authors, covers, and inline-image ordering are preserved from
-- the server-rendered legacy pages; images are served as local static assets.

insert into public.blog_posts (
    slug, title, excerpt, content_version, content,
    cover_image_source, cover_image_path, cover_image_alt,
    status, author_user_id, author_display_name, published_at, created_at, updated_at
)
values
(
    '2024-induction-day',
    '2024 Induction Day',
    'August 18th marks the start of a new year for PCA Youth Center. PCA Youth Center members, both new and returning, gathered at North Park for induction day, an enjoyable two hours of introductions and team bonding between the members of the 2024-2025 youth student council.',
    1,
    $content$[{"type":"paragraph","text":"August 18th marks the start of a new year for PCA Youth Center. PCA Youth Center members, both new and returning, gathered at North Park for induction day, an enjoyable two hours of introductions and team bonding between the members of the 2024-2025 youth student council."},{"type":"paragraph","text":"After the day started with an invigorating speech from the student council president and a brief introduction from the other position holding members, members gathered in the field to participate in an exciting round of the sandwich game, a game where each member says their name and adds an ingredient to the imaginary sandwich. Moving across the circle, each member recites the previous members’ names and corresponding sandwich ingredients before adding their own ingredient. Despite many forgotten ingredients, most members successfully learned most names."},{"type":"paragraph","text":"After adding some twists, like reciting the names and ingredients backward, the student council moved on to throwing a ball toward one another. In order to further help retain members’ names, the thrower had to address the receiver by their name."},{"type":"paragraph","text":"Next was a game similar to the concept of speed dating, where each person meets up with another member and gives a short introduction before moving on to another person after a minute. Conversation flowed as each member met their future fellow student council members and began to bond."},{"type":"paragraph","text":"Wrapping up the day was a classic, timeless game: Uno. Armed with eight decks of Uno cards, the student council split into three groups organized by grade level and cards were quickly dealt. The chatter continued as members munched on chips while trying their luck with wilds and reverses. PCA shirts were sold to new members as the games came to an end."},{"type":"paragraph","text":"The thrilling day concluded with a farewell speech from the president and information about the next upcoming meeting. PCA can’t wait to see all the new possibilities and opportunities this new year will bring!"}]$content$::jsonb,
    'local',
    'images/blog/2024-induction-day-cover.avif',
    '2024 Induction Day',
    'published',
    null,
    'Joanna Bi',
    '2024-09-07T18:15:47.858Z'::timestamptz,
    '2024-09-07T18:15:47.858Z'::timestamptz,
    '2024-09-07T18:15:47.858Z'::timestamptz
),
(
    'career-talk',
    'Career Talk',
    'During the Career Talk Event, we heard from four different presenters. They gave us important advice for our future self. It was a fascinating event because we learned about how to encounter challenges and embrace change.',
    1,
    $content$[{"type":"paragraph","text":"During the Career Talk Event, we heard from four different presenters. They gave us important advice for our future self. It was a fascinating event because we learned about how to encounter challenges and embrace change."},{"type":"paragraph","text":"Before we had this big event, we had to try and find ways to advertise on social media and talk to different schools about this event. The Social Media Team was able to create a poster and caption to post on Instagram. PCA also tried to advertise Career Talk to different school districts. Different PCA students were assigned to send an email to advertise Career Talk to each school. Many parents on WeChat were able to post and share this poster around their stories. PCA had to create a zoom meeting where the event would take place. We also sent thank you letters to the presenters for being able to join and talk with us."},{"type":"paragraph","text":"PCA had a blast listening to the presenters and learning loads of information during this event. Some takeaways from the two days of presenting were, “Failure is just a redirection, don’t give up.” We heard this from our wonderful speaker, Leonela Pascual. Another takeaway we heard from Yuan Tao was, “GPA and IQ will get you to a good position, but your attitude and connections are what will get you farther.” Helen Feinstein told us, “You did what you thought was best at the time.” The final takeaway from this event is from Annie Cui, “You do it for yourself and it’s all in your name.” We have heard some inspirational messages during this event which will help push many kids in the future."},{"type":"paragraph","text":"PCA is very grateful for all the people who signed up to listen to each presenter's talk. We want to thank the presenters for joining us because they are busy people. This event went really well and PCA will be definitely thinking about doing this next year!"}]$content$::jsonb,
    'local',
    'images/blog/career-talk-cover.avif',
    'Career Talk',
    'published',
    null,
    'Hanna Qian',
    '2024-01-22T03:58:35.637Z'::timestamptz,
    '2024-01-22T03:58:35.637Z'::timestamptz,
    '2024-01-22T03:58:35.637Z'::timestamptz
),
(
    'pca-fall-art-show',
    'PCA Fall Art Show',
    'With fall in the air, PCA held its annual art show at the Mount Lebanon Library for an afternoon filled with fun, excitement, and most importantly, beautiful art! A variety of activities were offered to make the event enjoyable for all ages, such as free drawing. A blind drawing activity was also...',
    1,
    $content$[{"type":"paragraph","text":"With fall in the air, PCA held its annual art show at the Mount Lebanon Library for an afternoon filled with fun, excitement, and most importantly, beautiful art! A variety of activities were offered to make the event enjoyable for all ages, such as free drawing. A blind drawing activity was also held where two partners put their cooperation and communication skills to the test. The drawer was blindfolded while the other gave directions. PCA members also drew arm paintings on participants, which was a big hit! One of the highlights of the event was the collaborative painting. Each person was given a small tile that they could personalize and glue onto the painting. With each person contributing to the painting, the result was an intricate painting that truly was special! The son of Hedy O’Biel, who is known for her expressive abstract paintings and two-time winner of the Jackson Pollock-Lee Krasner Foundation Award, spoke at the event. He shared with everyone a piece from her titled “Strength” and called on the audience for their personal interpretations on the meaning of the piece. Overall, the event was a success, emphasizing the deep impact that different forms of art can have."},{"type":"paragraph","text":"Check out Hedy’s amazing art here! https://www.hedyobeilart.com/"},{"type":"paragraph","text":"Created by: Angie Sun, Angelina Li, Andrew Li"}]$content$::jsonb,
    'local',
    'images/blog/pca-fall-art-show-cover.avif',
    'PCA Fall Art Show',
    'published',
    null,
    'liandrew2025',
    '2023-12-04T02:38:58.016Z'::timestamptz,
    '2023-12-04T02:38:58.016Z'::timestamptz,
    '2023-12-04T02:38:58.016Z'::timestamptz
),
(
    'pca-mid-autumn-festival',
    'PCA Mid-Autumn Festival',
    'Happy Fall! PCA held its Mid-Autumn festival this weekend at Mt.Lebo for the 2nd year with many fun activities and snacks! The Mid-Autumn Festival promotes Chinese history and culture. The holiday takes place every year on the 29th of September with huge celebrations. It is traditional to hang co...',
    1,
    $content$[{"type":"paragraph","text":"Happy Fall! PCA held its Mid-Autumn festival this weekend at Mt.Lebo for the 2nd year with many fun activities and snacks! The Mid-Autumn Festival promotes Chinese history and culture. The holiday takes place every year on the 29th of September with huge celebrations. It is traditional to hang colorful lanterns and eat delicious mooncakes. There were lanterns for sale that you could also decorate and personalize, which symbolize good fortune in Chinese culture. There were also mooncakes, a classic Chinese sweet treat."},{"type":"paragraph","text":"With various activities throughout the event, there was something for everyone! There was face painting, lanterns you could make and personalize with stickers, paints, letters, etc., paper cutting of all sorts of traditional pictures and patterns, and even air dry clay for guests to make clay sculptures with! Many parents came with their kids and said that it was a very fun experience and the kids loved socializing. In addition to the activities, many kids also enjoyed playing on the playground nearby."},{"type":"paragraph","text":"This event was a success, with lots of people showing up to attend! It was all smiles and laughter as PCA celebrated this monumental holiday and welcomed the new season."},{"type":"paragraph","text":"Written by : Angelina Li"}]$content$::jsonb,
    'local',
    'images/blog/pca-mid-autumn-festival-cover.avif',
    'PCA Mid-Autumn Festival',
    'published',
    null,
    'liandrew2025',
    '2023-10-06T11:46:19.678Z'::timestamptz,
    '2023-10-06T11:46:19.678Z'::timestamptz,
    '2023-10-06T11:46:19.678Z'::timestamptz
),
(
    'cultural-festival-1',
    'Cultural Festival',
    'The Chinese Cultural Festival at Mellon Park is where all the fun happened and delicious food was. The PCA gathered everyone together to do many activities such as face painting and making bookmarks.',
    1,
    $content$[{"type":"paragraph","text":"The Chinese Cultural Festival at Mellon Park is where all the fun happened and delicious food was. The PCA gathered everyone together to do many activities such as face painting and making bookmarks."},{"type":"paragraph","text":"Some background information of the Cultural Festival, its history and where it takes place every year. The Cultural Festival is an annual event in the Pittsburgh Chinese Cultural Center, or PCCC, and it is also the biggest annual event held in the Pittsburgh Chinese Community. It started in 2015, which means that it has been going on for eight years. It is usually a whole day event that would operate from 11 AM to 6 PM. The festival has an expected amount of five thousand people to join this event each year. Some activities for this festival include music and dance performances, eating Asian cuisine, and playing fun outdoor games."},{"type":"paragraph","text":"The PCA’s time at the Cultural Festival was a huge success, with more than enough volunteers able to help with different activities. As we asked the parents around us, they answered as it was an overall ten out of ten experience. There were amazing performances including Chinese dances, festive music, and yummy food. PCA had an exciting time at Mellon Park, and cannot wait to come back for next year's Chinese Cultural Festival!"},{"type":"paragraph","text":"PCA had a wonderful time with the Chinese Cultural Festival, as all members were able to help out and have fun! During the festival, we shared the culture and spread kindness to all the people."},{"type":"paragraph","text":"Blog Written By: Hannah Qian"}]$content$::jsonb,
    'local',
    'images/blog/cultural-festival-1-cover.avif',
    'Cultural Festival',
    'published',
    null,
    'liandrew2025',
    '2023-09-23T14:52:54.585Z'::timestamptz,
